function clone(value) {
  return JSON.parse(JSON.stringify(value));
}

function waitForMock(payload, delay = REQUEST_DELAY_MS) {
  return new Promise((resolve) => {
    globalThis.setTimeout(() => resolve(clone(payload)), delay);
  });
}

function normalize(value) {
  return String(value || '').trim().toLowerCase();
}

function countBy(items, fieldName) {
  return items.reduce((accumulator, item) => {
    const key = item[fieldName] || 'UNKNOWN';
    accumulator[key] = (accumulator[key] || 0) + 1;
    return accumulator;
  }, {});
}

function getActiveUserCount() {
  return mockUsers.filter((user) => user.status === 'ACTIVE').length;
}

function getPendingReviewCount() {
  return reviewQueue.filter((submission) => submission.status === 'PENDING').length;
}

function getReviewResultSummary() {
  const reviewedCounts = countBy(projectReviews, 'result');
  return {
    totalReviewed: projectReviews.length,
    pass: reviewedCounts.PASS || 0,
    fail: reviewedCounts.FAIL || 0,
    pending: getPendingReviewCount(),
  };
}

function getMentorPerformanceRows() {
  const mentors = mockUsers.filter((user) => user.role === 'MENTOR');

  return mentors.map((mentor) => {
    const reviews = projectReviews.filter((review) => review.mentorId === mentor.id);
    const assignments = mentorAssignments.filter(
      (assignment) => assignment.mentorId === mentor.id && assignment.status === 'ACTIVE',
    );
    const pending = reviewQueue.filter(
      (submission) => submission.mentorId === mentor.id && submission.status === 'PENDING',
    ).length;

    return {
      mentorId: mentor.id,
      mentorName: mentor.name,
      activeAssignments: assignments.length,
      reviewed: reviews.length,
      pass: reviews.filter((review) => review.result === 'PASS').length,
      fail: reviews.filter((review) => review.result === 'FAIL').length,
      pending,
      averageHoursToReview: mentor.id === 'user-mentor-001' ? 18 : 26,
    };
  });
}

function buildDashboardPayload() {
  const reviewSummary = getReviewResultSummary();

  return {
    generatedAt: new Date().toISOString(),
    summary: {
      totalUsers: mockUsers.length,
      activeUsers: getActiveUserCount(),
      mentors: mockUsers.filter((user) => user.role === 'MENTOR').length,
      learners: mockUsers.filter((user) => user.role === 'LEARNER').length,
